import{_ as a,o as r,c as l,a2 as d}from"./chunks/framework.ZhLefgN8.js";const b=JSON.parse('{"title":"奖励系统概览","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/rewards-overview.md","filePath":"zh-CN/rewards/rewards-overview.md"}'),i={name:"rewards/rewards-overview.md"};function e(o,t,h,n,s,p){return r(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="奖励系统概览" tabindex="-1">奖励系统概览 <a class="header-anchor" href="#奖励系统概览" aria-label="Permalink to &quot;奖励系统概览&quot;">​</a></h1><p>现金奖励与卡券奖励区别、发放流程、奖励状态及锁仓期机制说明。</p><h2 id="奖励类型" tabindex="-1">奖励类型 <a class="header-anchor" href="#奖励类型" aria-label="Permalink to &quot;奖励类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>奖励类型</th><th>说明</th><th>到账方式</th></tr></thead><tbody><tr><td>现金奖励</td><td>直接到账至您的账户余额，可用于交易或提现</td><td>自动到账，无需操作</td></tr><tr><td>卡券奖励</td><td>行情卡、股票卡、免佣卡、现金卡等功能性卡券</td><td>到账后可能需要手动激活</td></tr><tr><td>实物奖励</td><td>实体商品或电子兑换券（如咖啡券、礼品卡）</td><td>需主动领取或填写收货信息</td></tr><tr><td>道具奖励</td><td>倍数卡等活动专属道具，用于参与游戏化活动</td><td>自动到账，在「活动」页面查看和使用，不在「卡券」中显示</td></tr></tbody></table><p><strong>重要提醒：「现金奖励」与「现金卡」是两种不同产品</strong></p><ul><li>现金奖励：直接入账至账户余额，自动到账，无需操作，无账户类型限制</li><li>现金卡（属于卡券奖励）：需手动在「卡券」页面点击「激活」，仅限长桥证券（LB 账户）使用</li></ul><p>活动通知中如显示「获得现金奖励」，请在「奖励记录」确认具体奖励类型，若是现金卡则需按卡券操作步骤激活。</p><h3 id="道具奖励说明" tabindex="-1">道具奖励说明 <a class="header-anchor" href="#道具奖励说明" aria-label="Permalink to &quot;道具奖励说明&quot;">​</a></h3><p>道具是游戏化奖励，常见类型：</p><ul><li>倍数卡：使您在特定活动中的积分或任务币加倍（如 2 倍卡、3 倍卡），持有后参与对应活动时自动生效，无需手动激活</li><li>道具有固定有效期，过期后自动失效</li><li>道具奖励在 APP「活动」页面查看和使用，不在「卡券」中显示</li></ul><h2 id="如何查看奖励" tabindex="-1">如何查看奖励 <a class="header-anchor" href="#如何查看奖励" aria-label="Permalink to &quot;如何查看奖励&quot;">​</a></h2><ol><li>打开 APP，进入「我的」页面</li><li>点击「奖励记录」或「活动中心」</li><li>可查看所有奖励的类型、状态和到账时间</li></ol><h2 id="奖励发放流程" tabindex="-1">奖励发放流程 <a class="header-anchor" href="#奖励发放流程" aria-label="Permalink to &quot;奖励发放流程&quot;">​</a></h2><h3 id="自动发放" tabindex="-1">自动发放 <a class="header-anchor" href="#自动发放" aria-label="Permalink to &quot;自动发放&quot;">​</a></h3><p>达成活动条件后，系统会在约 10 分钟内自动处理并发放奖励：</p><ul><li>现金奖励直接进入账户余额</li><li>自动激活类卡券直接生效</li><li>若超过 30 分钟仍未收到奖励，可联系客服查询</li></ul><h3 id="需主动领取的情况" tabindex="-1">需主动领取的情况 <a class="header-anchor" href="#需主动领取的情况" aria-label="Permalink to &quot;需主动领取的情况&quot;">​</a></h3><ul><li>点击「激活」：某些卡券（如股票卡、现金卡）发放后需手动激活才能使用</li><li>点击「领取」：实物奖励或电子券需主动领取，领取后填写相关信息</li><li>部分活动需在任务完成页面点击「领取奖励」</li></ul><p>请在有效期内完成领取，逾期奖励可能失效。</p><h3 id="需审核的情况" tabindex="-1">需审核的情况 <a class="header-anchor" href="#需审核的情况" aria-label="Permalink to &quot;需审核的情况&quot;">​</a></h3><p>高价值奖励或特定活动可能需要人工审核：</p><ul><li>审核通常在 1-3 个工作日内完成（香港时间，周一至周五）</li><li>审核期间奖励状态显示为「审核中」</li><li>审核结果会通过 APP 通知或短信告知</li></ul><h3 id="到账时间说明" tabindex="-1">到账时间说明 <a class="header-anchor" href="#到账时间说明" aria-label="Permalink to &quot;到账时间说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>发放类型</th><th>预计到账时间</th></tr></thead><tbody><tr><td>自动发放（现金、自动激活卡券）</td><td>约 10 分钟</td></tr><tr><td>需人工审核的奖励</td><td>审核通过后最长 3 个工作日</td></tr><tr><td>My Link 积分</td><td>有锁仓期，请参考奖励记录中的「预计到账时间」字段</td></tr></tbody></table><h2 id="奖励状态说明" tabindex="-1">奖励状态说明 <a class="header-anchor" href="#奖励状态说明" aria-label="Permalink to &quot;奖励状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th><th>需要做什么</th></tr></thead><tbody><tr><td>待处理</td><td>系统已收到奖励申请，正在队列中等待处理</td><td>等待即可，无需操作</td></tr><tr><td>审核中</td><td>奖励正在由人工审核</td><td>等待审核结果，通常 1-3 个工作日</td></tr><tr><td>审核未通过</td><td>本次奖励不符合发放条件</td><td>查看活动规则确认是否满足条件；如有异议请联系客服</td></tr><tr><td>发放中</td><td>审核已通过，系统正在处理发放</td><td>等待即可，无需操作</td></tr><tr><td>已到账</td><td>奖励已成功发放</td><td>查看账户余额（现金奖励）/ 查看「卡券」列表（卡券奖励）/ 前往「活动」页面（道具奖励）</td></tr><tr><td>发放失败</td><td>发放过程中出现异常</td><td>系统会自动重试；若超过 24 小时仍失败，联系客服并提供活动名称和用户 ID</td></tr><tr><td>已取消</td><td>奖励超过有效期未达成条件，或违反活动规则被取消</td><td>确认活动条件是否满足；取消后相关联的卡券权益将同步失效</td></tr></tbody></table><h2 id="发放失败与自动重试" tabindex="-1">发放失败与自动重试 <a class="header-anchor" href="#发放失败与自动重试" aria-label="Permalink to &quot;发放失败与自动重试&quot;">​</a></h2><p>发放失败不代表永久失败，系统会自动重试：</p><ul><li>常见可重试原因：账户未开户（如股票卡需要港股账户）、网络临时故障</li><li>看到「发放失败」后，先等待 30 分钟观察是否自动恢复</li><li>若超过 24 小时仍显示发放失败，请联系客服，并提供活动名称和用户 ID</li><li>审核未通过、账户违规等属于非重试型失败，需人工介入处理</li></ul><h2 id="锁仓期机制" tabindex="-1">锁仓期机制 <a class="header-anchor" href="#锁仓期机制" aria-label="Permalink to &quot;锁仓期机制&quot;">​</a></h2><p>锁仓期（Lockup Period）是部分活动的核心条件：参与活动并获得奖励后，需要在规定期间内维持账户资产在一定水平，否则视为违约，奖励可能被扣回。</p><h3 id="锁仓期的触发方式" tabindex="-1">锁仓期的触发方式 <a class="header-anchor" href="#锁仓期的触发方式" aria-label="Permalink to &quot;锁仓期的触发方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>触发方式</th><th>说明</th></tr></thead><tbody><tr><td>入金锁仓</td><td>入金 N 万元后须保持 M 天不大额出金，账户净资产不低于要求金额</td></tr><tr><td>持仓锁仓</td><td>需持有特定股票或产品 M 天，期间不可卖出超过规定比例</td></tr><tr><td>资产锁仓</td><td>账户总资产（现金 + 持仓市值）在整个锁仓期内须维持在门槛以上</td></tr></tbody></table><h3 id="锁仓期计算规则" tabindex="-1">锁仓期计算规则 <a class="header-anchor" href="#锁仓期计算规则" aria-label="Permalink to &quot;锁仓期计算规则&quot;">​</a></h3><ul><li>锁仓期从奖励发放日（或活动约定的起算日）开始计算，非从入金日起算</li><li>以香港时间（HKT）为准，每日结算一次</li><li>部分活动按自然日计算，部分按工作日计算，以活动规则为准</li><li>持有多个活动的锁仓期时，各活动锁仓期独立计算，互不影响</li></ul><h3 id="违反锁仓期的后果" tabindex="-1">违反锁仓期的后果 <a class="header-anchor" href="#违反锁仓期的后果" aria-label="Permalink to &quot;违反锁仓期的后果&quot;">​</a></h3><p>违反锁仓条件（如在锁仓期内大额出金、卖出锁仓股票）可能导致：</p><ol><li>当次活动资格取消</li><li>已发放的现金奖励被扣回（从账户余额中直接扣除）</li><li>已发放的股票奖励被扣回（从持仓中强制卖出对应价值）</li><li>部分活动收取违约手续费</li></ol><blockquote><p>注意：锁仓期内的正常小额出金、手续费扣除等不一定触发违约，具体阈值以活动条款为准。</p></blockquote><h3 id="查看锁仓状态" tabindex="-1">查看锁仓状态 <a class="header-anchor" href="#查看锁仓状态" aria-label="Permalink to &quot;查看锁仓状态&quot;">​</a></h3><ul><li>APP「活动中心」→「我参与的活动」→ 点击具体活动，可查看： <ul><li>当前锁仓条件（需维持的资产金额）</li><li>剩余锁仓天数</li><li>当前账户资产是否满足要求</li></ul></li></ul><h3 id="奖励锁定状态" tabindex="-1">奖励锁定状态 <a class="header-anchor" href="#奖励锁定状态" aria-label="Permalink to &quot;奖励锁定状态&quot;">​</a></h3><p>奖励状态显示「锁定中（Lockup）」表示奖励已到账但处于锁仓期，锁仓期结束后系统自动解锁，变为可用状态。锁定期间不可提现或转出该部分资金。</p><h2 id="奖励领取与状态答疑" tabindex="-1">奖励领取与状态答疑 <a class="header-anchor" href="#奖励领取与状态答疑" aria-label="Permalink to &quot;奖励领取与状态答疑&quot;">​</a></h2><p><strong>Q：达成活动条件后多久能收到奖励？</strong></p><p>A：大多数奖励在达成条件后约 10 分钟内自动发放。若活动需要人工审核，则需 1-3 个工作日。建议在 APP 的奖励记录页面查看实时状态。</p><hr><p><strong>Q：现金奖励和现金卡有什么区别？</strong></p><p>A：现金奖励直接进入账户余额，可用于交易或提现，无需额外操作，无账户类型限制。现金卡属于卡券奖励，不会自动入账，需在「卡券」页面手动点击「激活」，仅限长桥证券（LB<br> 账户）使用。</p><hr><p><strong>Q：奖励有有效期吗？</strong></p><p>A：有。现金奖励到账后通常永久有效；卡券奖励有明确有效期（从发放日或激活日起计算）；实物/电子券有固定截止日期。请在活动页面或奖励详情中查看具体有效期。</p><hr><p><strong>Q：奖励状态一直显示「待处理」怎么办？</strong></p><p>A：正常情况下「待处理」状态会在 30 分钟内更新。若超过 2 小时仍无变化，请联系客服，并提供活动名称和您的用户 ID。</p><hr><p><strong>Q：审核未通过是什么原因？</strong></p><p>A：常见原因包括：未完全满足活动条件（如入金金额不足、持仓时间不够）、账户存在异常、同一用户重复参与等。请仔细核对活动规则，如有异议可联系客服申诉。</p><hr><p><strong>Q：奖励显示「发放失败」，还能拿到吗？</strong></p><p>A：发放失败不代表永久失败，系统通常会自动重试。请先等待约 30 分钟，观察状态是否自动恢复。若超过 24 小时仍显示发放失败，请联系客服，提供活动名称和用户<br> ID。</p><hr><p><strong>Q：完成了活动任务，但奖励记录里没有显示？</strong></p><p>A：请先确认活动是否要求手动点击「领取」。如已操作但仍未显示，可能存在系统延迟（约 10 分钟），请稍后刷新页面再查看。若仍未出现，请联系客服。</p><hr><p><strong>Q：现金奖励到账后在哪里查看？</strong></p><p>A：现金奖励会进入您对应货币的账户余额（如港元账户）。可在「资产」或「账户」页面查看余额变动，也可查看账户流水记录。</p><hr><p><strong>Q：我没开户，奖励会发吗？</strong></p><p>A：</p><ul><li>现金奖励：系统保留发放记录，等完成开户（KYC）后自动重新发放，无需联系客服</li><li>现金卡：须开通长桥证券（LB 账户）后，在「卡券」页面手动激活</li><li>股票卡：需开通对应市场账户（如港股账户）后才能发放</li></ul><hr><p><strong>Q：活动说有锁定条件，违反了会怎样？</strong></p><p>A：违反锁定条件（如在锁定期内大额出金导致账户资产低于要求）可能导致取消本次活动资格，甚至扣取已发放的奖励或相应手续费。您可以在「活动中心」→「我参与的活动」中查看当前锁定条件和剩余锁定时间。</p><hr><p><strong>Q：同一个活动，为什么有人立刻到账有人要审核？</strong></p><p>A：不同用户的账户风险评分不同，高风险评分的账户需要人工审核，正常审核时间为 1-3 个工作日。这是平台正常的风控机制，并不代表账户有问题。</p><hr><p><strong>Q：活动名额满了，我完成条件还能拿到奖励吗？</strong></p><p>A：不能。部分活动采用先到先得机制，名额满后即使完成活动条件也无法获得奖励。建议在看到感兴趣的活动后第一时间完成任务。</p><h2 id="参与资格与奖励通用限制" tabindex="-1">参与资格与奖励通用限制 <a class="header-anchor" href="#参与资格与奖励通用限制" aria-label="Permalink to &quot;参与资格与奖励通用限制&quot;">​</a></h2><ul><li>所有时间均以香港时间（HKT，UTC+8）为准，包括活动截止时间和审核时限</li><li>工作日指香港法定工作日（周一至周五，不含公众假期）</li><li>奖励仅限发放账户本人使用，不可转让</li><li>若账户处于冻结或受限状态，奖励可能无法正常发放</li><li>如对审核结果有异议，请在活动结束后 30 天内联系客服申诉</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards/奖励记录">奖励记录</a> — 查看奖励明细</li><li><a href="/wiki/rewards/卡券系统">卡券系统</a> — 卡券使用规则</li></ul>',84)])])}const c=a(i,[["render",e]]);export{b as __pageData,c as default};
